package com.example.myapp.deeplink;

import android.content.Context;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import java.util.List;

public final class DeepLinkHandlerActivity extends AppCompatActivity {

    public static final String SCHEME = "myapp";

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        handleIntent(getIntent());
        finish();
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
        finish();
    }

    private void handleIntent(@Nullable Intent intent) {
        Uri uri = intent != null ? intent.getData() : null;
        Intent target = DeepLinkRouter.route(this, uri);

        if (target == null) {
            target = new Intent(this, MainActivity.class);
        }

        target.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP | Intent.FLAG_ACTIVITY_SINGLE_TOP);
        startActivity(target);
    }

    public static final class DeepLinkRouter {

        @Nullable
        public static Intent route(@NonNull Context context, @Nullable Uri uri) {
            if (uri == null) return null;
            if (!SCHEME.equalsIgnoreCase(uri.getScheme())) return null;

            String host = uri.getHost(); // for myapp://profile/123 -> host="profile"
            List<String> segments = uri.getPathSegments(); // ["123"]

            if (TextUtils.isEmpty(host)) return null;

            switch (host.toLowerCase()) {
                case "profile": {
                    String userId = (segments != null && segments.size() >= 1) ? segments.get(0) : null;
                    if (TextUtils.isEmpty(userId)) return new Intent(context, MainActivity.class);

                    Intent i = new Intent(context, ProfileActivity.class);
                    i.putExtra(ProfileActivity.EXTRA_USER_ID, userId);
                    i.setData(uri);
                    return i;
                }
                case "payment": {
                    String action = (segments != null && segments.size() >= 1) ? segments.get(0) : null;
                    if ("confirm".equalsIgnoreCase(action)) {
                        Intent i = new Intent(context, PaymentConfirmActivity.class);
                        i.setData(uri);
                        return i;
                    }
                    return new Intent(context, MainActivity.class);
                }
                case "admin": {
                    String section = (segments != null && segments.size() >= 1) ? segments.get(0) : null;
                    if ("settings".equalsIgnoreCase(section)) {
                        Intent i = new Intent(context, AdminSettingsActivity.class);
                        i.setData(uri);
                        return i;
                    }
                    return new Intent(context, MainActivity.class);
                }
                default:
                    return new Intent(context, MainActivity.class);
            }
        }

        private DeepLinkRouter() {}
    }
}

